import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../../context/AuthContext';
import AnimatedNumber from '../../components/AnimatedNumber';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const SEMESTERS = [1,2,3,4,5,6,7,8];
const STATUS_BADGE = { submitted:'badge-yellow', approved:'badge-green', rejected:'badge-red' };

function DetailModal({ title, icon, onClose, children, count, filters }) {
  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxWidth: 760 }}>
        <div className="modal-header">
          <span className="modal-title">{icon} {title}</span>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        {filters && (
          <div style={{ padding:'12px 20px', borderBottom:'1px solid var(--border)', background:'#f8fafc', display:'flex', gap:10, flexWrap:'wrap' }}>
            {filters}
          </div>
        )}
        <div style={{ maxHeight:'60vh', overflowY:'auto' }}>{children}</div>
        <div style={{ padding:'12px 20px', borderTop:'1px solid var(--border)', fontSize:13, color:'var(--text-muted)', background:'#f8fafc' }}>
          Showing: <strong>{count}</strong> record{count !== 1 ? 's' : ''}
        </div>
      </div>
    </div>
  );
}

export default function FacultyDashboard() {
  const { user } = useAuth();
  const [data,    setData]    = useState(null);
  const [loading, setLoading] = useState(true);
  const [modal,   setModal]   = useState(null);
  const [allData, setAllData] = useState([]);
  const [filtered,setFiltered]= useState([]);
  const [loadingModal, setLoadingModal] = useState(false);

  // Filters
  const [fSearch, setFSearch] = useState('');
  const [fSem,    setFSem]    = useState('');
  const [fMid,    setFMid]    = useState('');
  const [fStatus, setFStatus] = useState('');

  useEffect(() => {
    axios.get('/api/faculty/stats')
      .then(res => { setData(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  useEffect(() => {
    if (!modal) return;
    let result = [...allData];
    if (fSearch) {
      const q = fSearch.toLowerCase();
      result = result.filter(r =>
        r.name?.toLowerCase().includes(q) ||
        r.student?.name?.toLowerCase().includes(q) ||
        r.student?.rollNumber?.toLowerCase().includes(q) ||
        r.subject?.name?.toLowerCase().includes(q) ||
        r.code?.toLowerCase().includes(q)
      );
    }
    if (fSem) result = result.filter(r => (r.semester || r.subject?.semester) === Number(fSem));
    if (fMid) result = result.filter(r => r.midExam === fMid);
    if (fStatus) result = result.filter(r => r.status === fStatus);
    setFiltered(result);
  }, [allData, fSearch, fSem, fMid, fStatus, modal]);

  const openModal = async (type, title, icon) => {
    setModal({ type, title, icon });
    setAllData([]); setFiltered([]);
    setFSearch(''); setFSem(''); setFMid(''); setFStatus('');
    setLoadingModal(true);
    try {
      if (type === 'assignedSubjects') {
        // Load across all semesters
        const results = [];
        for (const sem of SEMESTERS) {
          try {
            const res = await axios.get('/api/faculty/subjects', { params: { semester: sem } });
            if (res.data.subjects?.length) results.push(...res.data.subjects.map(s => ({ ...s, semester: sem })));
          } catch {}
        }
        setAllData(results);
      } else {
        const params = {};
        if (type === 'pending')  params.status = 'submitted';
        if (type === 'approved') params.status = 'approved';
        if (type === 'rejected') params.status = 'rejected';
        const res = await axios.get('/api/faculty/marks', { params: type === 'submitted' ? {} : params });
        setAllData(res.data.marks);
      }
    } catch { setAllData([]); }
    finally { setLoadingModal(false); }
  };

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
  if (!data)   return <div className="empty-state"><div className="empty-icon">⚠️</div><div className="empty-text">Failed to load</div></div>;

  const { stats } = data;

  const chartData = [
    { name:'Total',    value:stats.submittedMarks, fill:'#1a56db' },
    { name:'Pending',  value:stats.pendingMarks,   fill:'#f59e0b' },
    { name:'Approved', value:stats.approvedMarks,  fill:'#10b981' },
    { name:'Rejected', value:stats.rejectedMarks,  fill:'#ef4444' },
  ];

  const statCards = [
    { key:'submitted',        value:stats.submittedMarks,  label:'Total Marks Entered', icon:'📊', color:'blue',   title:'All Marks Entries'  },
    { key:'pending',          value:stats.pendingMarks,    label:'Pending Approval',    icon:'⏳', color:'yellow', title:'Pending Marks'      },
    { key:'approved',         value:stats.approvedMarks,   label:'Approved',            icon:'✅', color:'green',  title:'Approved Marks'     },
    { key:'rejected',         value:stats.rejectedMarks,   label:'Rejected',            icon:'❌', color:'red',    title:'Rejected Marks'     },
    { key:'assignedSubjects', value:stats.assignedSubjects,label:'Assigned Subjects',   icon:'📚', color:'cyan',   title:'My Assigned Subjects'},
  ];

  const renderFilters = () => {
    if (!modal) return null;
    const isMarks    = modal.type !== 'assignedSubjects';
    const isSubjects = modal.type === 'assignedSubjects';
    return (
      <>
        <input className="form-input-sm" style={{ width:180 }} placeholder="🔍 Search..." value={fSearch} onChange={e => setFSearch(e.target.value)} />
        <select className="form-select" style={{ width:150 }} value={fSem} onChange={e => setFSem(e.target.value)}>
          <option value="">All Semesters</option>
          {SEMESTERS.map(s => <option key={s} value={s}>Semester {s}</option>)}
        </select>
        {isMarks && (
          <select className="form-select" style={{ width:130 }} value={fMid} onChange={e => setFMid(e.target.value)}>
            <option value="">All Exams</option>
            <option value="Mid-1">Mid-1</option>
            <option value="Mid-2">Mid-2</option>
          </select>
        )}
        {isMarks && (
          <select className="form-select" style={{ width:140 }} value={fStatus} onChange={e => setFStatus(e.target.value)}>
            <option value="">All Status</option>
            <option value="submitted">Pending</option>
            <option value="approved">Approved</option>
            <option value="rejected">Rejected</option>
          </select>
        )}
        {(fSearch || fSem || fMid || fStatus) && (
          <button className="btn btn-outline btn-sm" onClick={() => { setFSearch(''); setFSem(''); setFMid(''); setFStatus(''); }}>✕ Clear</button>
        )}
      </>
    );
  };

  const renderContent = () => {
    if (loadingModal) return <div className="empty-state" style={{ padding:48 }}><div className="spinner" style={{ margin:'0 auto' }}></div></div>;
    if (!filtered.length) return <div className="empty-state"><div className="empty-icon">📭</div><div className="empty-text">No records found</div></div>;

    if (modal.type === 'assignedSubjects') return (
      <table>
        <thead><tr><th>#</th><th>Subject Name</th><th>Code</th><th>Semester</th><th>My Sections</th></tr></thead>
        <tbody>{filtered.map((s,i) => (
          <tr key={`${s._id}-${i}`}><td>{i+1}</td>
            <td className="fw-600">{s.name}</td>
            <td><span className="badge badge-purple">{s.code}</span></td>
            <td>Sem {s.semester}</td>
            <td>
              {s.mySections?.length ? s.mySections.map(sec => (
                <span key={sec.sectionId} className="badge badge-blue" style={{ marginRight:4 }}>Sec {sec.sectionName}</span>
              )) : '—'}
            </td>
          </tr>
        ))}</tbody>
      </table>
    );

    return (
      <table>
        <thead><tr><th>#</th><th>Student</th><th>Roll No</th><th>Subject</th><th>Exam</th><th>Marks</th><th>Status</th></tr></thead>
        <tbody>{filtered.map((m,i) => (
          <tr key={m._id}><td>{i+1}</td>
            <td className="fw-600">{m.student?.name}</td>
            <td style={{ fontFamily:'monospace',fontSize:12 }}>{m.student?.rollNumber}</td>
            <td>{m.subject?.name}</td>
            <td><span className="badge badge-blue">{m.midExam}</span></td>
            <td className="fw-600">{m.totalMarks}/30</td>
            <td><span className={`badge ${STATUS_BADGE[m.status]||'badge-gray'}`}>{m.status}</span>
              {m.isLocked && <span className="badge badge-red" style={{ marginLeft:4 }}>🔒</span>}
            </td>
          </tr>
        ))}</tbody>
      </table>
    );
  };

  return (
    <div>
      <div className="info-box" style={{ marginBottom:20 }}>
        👩‍🏫 Welcome, <strong>{user?.name}</strong> | Dept: <strong>{user?.department?.name}</strong>
      </div>

      <div className="stats-grid">
        {statCards.map((card, idx) => (
          <div key={card.key}
            className={`stat-card ${card.color} stat-card-animated`}
            style={{ '--delay':`${idx * 0.08}s`, cursor:'pointer', userSelect:'none' }}
            onClick={() => openModal(card.key, card.title, card.icon)}
            title={`Click to view ${card.title}`}
          >
            <div className="stat-icon">{card.icon}</div>
            <div>
              <div className="stat-value"><AnimatedNumber value={card.value} /></div>
              <div className="stat-label">{card.label}</div>
              <div style={{ fontSize:10, color:'var(--primary)', marginTop:2, fontWeight:600 }}>Click to view →</div>
            </div>
          </div>
        ))}
      </div>

      <div className="card">
        <div className="card-header"><span className="card-title">📊 Marks Submission Summary</span></div>
        <div className="card-body">
          <div className="chart-container">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <XAxis dataKey="name"/><YAxis allowDecimals={false}/><Tooltip/>
                <Bar dataKey="value" radius={[4,4,0,0]}>{chartData.map((e,i)=><Cell key={i} fill={e.fill}/>)}</Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {modal && (
        <DetailModal title={modal.title} icon={modal.icon} onClose={() => { setModal(null); setAllData([]); setFiltered([]); }} count={filtered.length} filters={renderFilters()}>
          {renderContent()}
        </DetailModal>
      )}
    </div>
  );
}
